const COLORS = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
  bold: '\x1b[1m',
};

const CONFIG = {
  nodeVersion: process.env.REQUIRED_NODE_VERSION || '18',
  deployTarget: process.env.DEPLOY_TARGET || 'production',
  deployHost: process.env.DEPLOY_HOST || 'deploy.example.com',
  deployUser: process.env.DEPLOY_USER || 'deploy',
  deployPath: process.env.DEPLOY_PATH || '/var/www/app',
  deployMethod: process.env.DEPLOY_METHOD || 'rsync', // rsync | docker | pm2
  buildDir: process.env.BUILD_DIR || 'dist',
  testTimeout: parseInt(process.env.TEST_TIMEOUT) || 120000,
  maxRetries: parseInt(process.env.MAX_RETRIES) || 3,
  parallelTests: process.env.PARALLEL_TESTS !== 'false',
  skipTests: process.env.SKIP_TESTS === 'true',
  skipLint: process.env.SKIP_LINT === 'true',
  skipBuild: process.env.SKIP_BUILD === 'true',
  dryRun: process.env.DRY_RUN === 'true',
  cacheDir: process.env.CACHE_DIR || path.join(os.tmpdir(), 'cicd-cache'),
  artifactDir: process.env.ARTIFACT_DIR || 'artifacts',
  healthCheckUrl: process.env.HEALTH_CHECK_URL || '',
  healthCheckTimeout: parseInt(process.env.HEALTH_CHECK_TIMEOUT) || 60000,
  rollbackOnFailure: process.env.ROLLBACK_ON_FAILURE !== 'false',
  notifySlack: process.env.SLACK_WEBHOOK_URL || '',
  notifyEmail: process.env.NOTIFY_EMAIL || '',
  dockerImage: process.env.DOCKER_IMAGE || 'app',
  dockerRegistry: process.env.DOCKER_REGISTRY || '',
  pm2AppName: process.env.PM2_APP_NAME || 'app',
};

// Pipeline state
const pipelineState = {
  startTime: Date.now(),
  stages: [],
  currentStage: null,
  errors: [],
  warnings: [],
  commitHash: '',
  branch: '',
  buildNumber: process.env.BUILD_NUMBER || Date.now().toString(),
  previousDeployHash: '',
};

// ============================================================
// Utility Functions
// ============================================================

function log(message, color = 'reset') {
  const timestamp = new Date().toISOString();
  console.log(`${COLORS[color]}[${timestamp}] ${message}${COLORS.reset}`);
}

function logStage(stageName) {
  const separator = '='.repeat(60);
  console.log(`\n${COLORS.bold}${COLORS.cyan}${separator}`);
  console.log(`  STAGE: ${stageName}`);
  console.log(`${separator}${COLORS.reset}\n`);
}

function logSuccess(message) {
  log(`✅ ${message}`, 'green');
}

function logError(message) {
  log(`❌ ${message}`, 'red');
}

function logWarning(message) {
  log(`⚠️  ${message}`, 'yellow');
  pipelineState.warnings.push(message);
}

function logInfo(message) {
  log(`ℹ️  ${message}`, 'blue');
}

function exec(command, options = {}) {
  const defaults = {
    stdio: 'pipe',
    encoding: 'utf-8',
    timeout: 300000, // 5 min default timeout
    env: { ...process.env, FORCE_COLOR: '1' },
  };
  const opts = { ...defaults, ...options };

  logInfo(`Executing: ${command}`);
  try {
    const result = execSync(command, opts);
    return result ? result.trim() : '';
  } catch (error) {
    if (options.ignoreError) {
      logWarning(`Command failed (ignored): ${command}`);
      return '';
    }
    throw error;
  }
}

function execWithRetry(command, retries = CONFIG.maxRetries, options = {}) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return exec(command, options);
    } catch (error) {
      if (attempt === retries) {
        throw error;
      }
      logWarning(`Attempt ${attempt}/${retries} failed for: ${command}. Retrying in ${attempt * 2}s...`);
      execSync(`sleep ${attempt * 2}`);
    }
  }
}

function fileExists(filePath) {
  return fs.existsSync(filePath);
}

function readJson(filePath) {
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf-8'));
  } catch {
    return null;
  }
}

function writeJson(filePath, data) {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2));
}

function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

function getElapsedTime(startTime) {
  const elapsed = Date.now() - startTime;
  const seconds = Math.floor(elapsed / 1000);
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = seconds % 60;
  if (minutes > 0) {
    return `${minutes}m ${remainingSeconds}s`;
  }
  return `${seconds}s`;
}

function generateChecksum(filePath) {
  try {
    if (process.platform === 'darwin') {
      return exec(`md5 -q ${filePath}`);
    }
    return exec(`md5sum ${filePath}`).split(' ')[0];
  } catch {
    return '';
  }
}

// ============================================================
// Stage Tracking
// ============================================================

function startStage(name) {
  logStage(name);
  const stage = {
    name,
    startTime: Date.now(),
    status: 'running',
    duration: null,
  };
  pipelineState.currentStage = stage;
  pipelineState.stages.push(stage);
  return stage;
}

function endStage(stage, status = 'success') {
  stage.status = status;
  stage.duration = Date.now() - stage.startTime;
  const elapsed = getElapsedTime(stage.startTime);

  if (status === 'success') {
    logSuccess(`Stage "${stage.name}" completed in ${elapsed}`);
  } else if (status === 'skipped') {
    logWarning(`Stage "${stage.name}" skipped`);
  } else {
    logError(`Stage "${stage.name}" failed after ${elapsed}`);
  }
}

async function runStage(name, fn, options = {}) {
  const stage = startStage(name);
  try {
    if (options.skip) {
      endStage(stage, 'skipped');
      return null;
    }
    const result = await fn();
    endStage(stage, 'success');
    return result;
  } catch (error) {
    endStage(stage, 'failed');
    pipelineState.errors.push({ stage: name, error: error.message });

    if (options.continueOnError) {
      logWarning(`Continuing despite failure in "${name}"`);
      return null;
    }
    throw error;
  }
}

