async function stageEnvironmentCheck() {
  // Check Node.js version
  const nodeVersion = process.version;
  logInfo(`Node.js version: ${nodeVersion}`);

  const majorVersion = parseInt(nodeVersion.slice(1).split('.')[0]);
  const requiredMajor = parseInt(CONFIG.nodeVersion);
  if (majorVersion < requiredMajor) {
    throw new Error(`Node.js ${CONFIG.nodeVersion}+ required, found ${nodeVersion}`);
  }

  // Check npm version
  const npmVersion = exec('npm --version');
  logInfo(`npm version: ${npmVersion}`);

  // Check available disk space
  try {
    const diskSpace = exec('df -h . | tail -1');
    logInfo(`Disk space: ${diskSpace}`);
  } catch {
    logWarning('Could not check disk space');
  }

  // Check memory
  const totalMem = Math.round(os.totalmem() / 1024 / 1024 / 1024 * 10) / 10;
  const freeMem = Math.round(os.freemem() / 1024 / 1024 / 1024 * 10) / 10;
  logInfo(`Memory: ${freeMem}GB free / ${totalMem}GB total`);

  // Get git info
  try {
    pipelineState.commitHash = exec('git rev-parse HEAD');
    pipelineState.branch = exec('git rev-parse --abbrev-ref HEAD');
    const commitMessage = exec('git log -1 --pretty=%B');
    logInfo(`Branch: ${pipelineState.branch}`);
    logInfo(`Commit: ${pipelineState.commitHash.substring(0, 8)}`);
    logInfo(`Message: ${commitMessage}`);
  } catch {
    logWarning('Not a git repository or git not available');
  }

  // Check for required files
  if (!fileExists('package.json')) {
    throw new Error('package.json not found in current directory');
  }

  const pkg = readJson('package.json');
  logInfo(`Project: ${pkg.name}@${pkg.version}`);

  // Check for required tools based on deploy method
  if (CONFIG.deployMethod === 'docker') {
    try {
      exec('docker --version');
      logInfo('Docker is available');
    } catch {
      throw new Error('Docker is required but not found');
    }
  }

  if (CONFIG.deployMethod === 'rsync') {
    try {
      exec('rsync --version', { ignoreError: true });
      logInfo('rsync is available');
    } catch {
      logWarning('rsync not found, will fall back to scp');
    }
  }

  return { nodeVersion, npmVersion, pkg };
}

async function stageInstallDependencies() {
  const lockFile = fileExists('package-lock.json')
    ? 'package-lock.json'
    : fileExists('yarn.lock')
      ? 'yarn.lock'
      : fileExists('pnpm-lock.yaml')
        ? 'pnpm-lock.yaml'
        : null;

  let packageManager = 'npm';
  let installCommand = 'npm ci --prefer-offline --no-audit --no-fund';

  if (lockFile === 'yarn.lock') {
    packageManager = 'yarn';
    installCommand = 'yarn install --frozen-lockfile --non-interactive';
    try {
      exec('yarn --version');
    } catch {
      logInfo('Installing yarn...');
      exec('npm install -g yarn');
    }
  } else if (lockFile === 'pnpm-lock.yaml') {
    packageManager = 'pnpm';
    installCommand = 'pnpm install --frozen-lockfile';
    try {
      exec('pnpm --version');
    } catch {
      logInfo('Installing pnpm...');
      exec('npm install -g pnpm');
    }
  } else if (!lockFile) {
    logWarning('No lock file found. Using npm install (not recommended for CI)');
    installCommand = 'npm install --no-audit --no-fund';
  }

  logInfo(`Package manager: ${packageManager}`);
  logInfo(`Lock file: ${lockFile || 'none'}`);

  // Cache check
  const cacheKey = lockFile ? generateChecksum(lockFile) : '';
  const cacheMarker = path.join('node_modules', '.cache-key');

  if (fileExists(cacheMarker)) {
    const cachedKey = fs.readFileSync(cacheMarker, 'utf-8').trim();
    if (cachedKey === cacheKey && cacheKey !== '') {
      logSuccess('Dependencies cache is valid, skipping install');
      return { packageManager, cached: true };
    }
  }

  // Install dependencies with retry
  execWithRetry(installCommand, CONFIG.maxRetries, { stdio: 'inherit' });

  // Write cache marker
  if (cacheKey) {
    ensureDir('node_modules');
    fs.writeFileSync(cacheMarker, cacheKey);
  }

  // Verify node_modules
  if (!fileExists('node_modules')) {
    throw new Error('node_modules directory not created after install');
  }

  return { packageManager, cached: false };
}

async function stageLinting() {
  const pkg = readJson('package.json');
  const scripts = pkg.scripts || {};

  const lintTasks = [];

  // ESLint
  if (scripts.lint) {
    lintTasks.push({ name: 'lint', command: 'npm run lint' });
  } else if (fileExists('.eslintrc') || fileExists('.eslintrc.js') || fileExists('.eslintrc.json') || fileExists('.eslintrc.yml') || pkg.eslintConfig) {
    lintTasks.push({ name: 'eslint', command: 'npx eslint . --ext .js,.jsx,.ts,.tsx --max-warnings 0' });
  }

  // TypeScript type checking
  if (scripts['type-check']) {
    lintTasks.push({ name: 'type-check', command: 'npm run type-check' });
  } else if (fileExists('tsconfig.json')) {
    lintTasks.push({ name: 'tsc', command: 'npx tsc --noEmit' });
  }

  // Prettier check
  if (scripts['format:check']) {
    lintTasks.push({ name: 'format', command: 'npm run format:check' });
  }

  if (lintTasks.length === 0) {
    logWarning('No linting configuration found, skipping');
    return { skipped: true };
  }

  const results = [];
  for (const task of lintTasks) {
    logInfo(`Running ${task.name}...`);
    try {
      exec(task.command, { stdio: 'inherit', timeout: 120000 });
      logSuccess(`${task.name} passed`);
      results.push({ name: task.name, status: 'passed' });
    } catch (error) {
      logError(`${task.name} failed`);
      results.push({ name: task.name, status: 'failed' });
      throw new Error(`Linting failed: ${task.name}`);
    }
  }

  return { results };
}

